-- HaynesPro chassis crawl → catalog ingest
-- Source crawl: scrapers/output/haynespro-crawl-honda-civic-x-fk-2026-05-23.json
-- HaynesPro modelId: d_319001478 (Civic X (FK, FC))
-- Crawl fetched_at: 2026-05-23T09:16:18.400Z
-- Target catalog generation_id: 1
-- Engines: P10A4, P10A2, L15B7, L15BA, L15BB, R16B2, N16A1, R18Z1, K20C2, K20C1
-- Generated by scrapers/haynespro/ingest_to_sql.ts on 2026-05-23T09:33:50.168Z

SET NAMES utf8mb4;

-- 1. HaynesPro source row (is_public=0, citation only for audit trail)
SET @s_haynes := (SELECT id FROM sources WHERE url = 'https://www.workshopdata.com/touch/site/layout/modelTypesList?modelId=d_319001478' ORDER BY id DESC LIMIT 1);

-- 2. Engines — auto-insert any not yet in catalog

-- 3. fluid_specs — engine_oil + coolant scoped to gen_id 1
SET @gen := 1;


-- 4. spec_sources — link inserted fluid_specs rows to the HaynesPro source
SELECT 'fluid_specs', fs.id, @s_haynes
FROM fluid_specs fs
JOIN engines e ON e.id = fs.engine_id
WHERE fs.generation_id = @gen
  AND e.code IN ('P10A4', 'P10A2', 'L15B7', 'L15BA', 'L15BB', 'R16B2', 'N16A1', 'R18Z1', 'K20C2', 'K20C1')
  AND fs.fluid_type IN ('engine_oil', 'coolant');

-- 5. Audit
SELECT e.code, COUNT(fs.id) AS rows_count,
       GROUP_CONCAT(DISTINCT CONCAT(fs.fluid_type, ' ', fs.capacity_l, 'L ', COALESCE(fs.viscosity,''), ' ', COALESCE(fs.spec_standard,'')) SEPARATOR ' | ') AS specs
FROM fluid_specs fs
JOIN engines e ON e.id = fs.engine_id
WHERE fs.generation_id = @gen
  AND e.code IN ('P10A4', 'P10A2', 'L15B7', 'L15BA', 'L15BB', 'R16B2', 'N16A1', 'R18Z1', 'K20C2', 'K20C1')
GROUP BY e.code ORDER BY e.code;
